mapper.select:
SELECT id, name, model, serial_no, max_speed_kmh, flight_time_min, payload_kg, battery_mah, ai_score, created_at, updated_at
FROM drone
WHERE id = #{id}

SELECT id, name, model, serial_no, max_speed_kmh, flight_time_min, payload_kg, battery_mah, ai_score, created_at, updated_at
FROM drone
WHERE serial_no = #{serialNo}

SELECT id, name, model, serial_no, max_speed_kmh, flight_time_min, payload_kg, battery_mah, ai_score, created_at, updated_at FROM drone
AND (name LIKE #{keywordLike} OR model LIKE #{keywordLike} OR serial_no LIKE #{keywordLike})
ORDER BY id DESC LIMIT #{pageSize} OFFSET #{offset}
